PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE `users` (`id` integer PRIMARY KEY AUTOINCREMENT,`username` varchar(50),`email` varchar(100),`password` varchar(255),`is_active` numeric DEFAULT true,`is_verified` numeric DEFAULT false,`is_admin` numeric DEFAULT false,`nickname` varchar(50),`avatar` varchar(255),`theme` varchar(20) DEFAULT "light",`language` varchar(10) DEFAULT "zh-CN",`timezone` varchar(50) DEFAULT "Asia/Shanghai",`email_notifications` numeric DEFAULT true,`abnormal_login_alert_enabled` numeric DEFAULT true,`notification_types` text,`push_notifications` numeric DEFAULT true,`data_sharing` numeric DEFAULT true,`analytics` numeric DEFAULT true,`balance` decimal(10,2) DEFAULT 0,`invited_by` integer,`invite_code_used` varchar(20),`total_invite_count` integer DEFAULT 0,`total_invite_reward` decimal(10,2) DEFAULT 0,`user_level_id` integer,`total_consumption` decimal(10,2) DEFAULT 0,`level_expires_at` datetime,`special_node_subscription_type` varchar(20) DEFAULT "both",`special_node_expires_at` datetime,`telegram_id` integer,`telegram_username` varchar(100),`notes` text,`verification_token` varchar(255),`verification_expires` datetime,`reset_token` varchar(255),`reset_expires` datetime,`created_at` datetime,`updated_at` datetime,`last_login` datetime, `notify_order` numeric DEFAULT true, `notify_expiry` numeric DEFAULT true, `notify_subscription` numeric DEFAULT true);
CREATE TABLE `token_blacklist` (`id` integer PRIMARY KEY AUTOINCREMENT,`token_hash` varchar(255) NOT NULL,`user_id` integer NOT NULL,`expires_at` datetime NOT NULL,`created_at` datetime);
CREATE TABLE `subscriptions` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`package_id` integer,`subscription_url` varchar(100),`device_limit` integer,`current_devices` integer DEFAULT 0,`universal_count` integer DEFAULT 0,`clash_count` integer DEFAULT 0,`surge_count` integer DEFAULT 0,`quan_x_count` integer DEFAULT 0,`shadowrocket_count` integer DEFAULT 0,`is_active` numeric DEFAULT true,`status` varchar(20) DEFAULT "active",`expire_time` datetime,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `subscription_resets` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`subscription_id` integer,`reset_type` varchar(50),`reason` text,`old_subscription_url` varchar(255),`new_subscription_url` varchar(255),`device_count_before` integer DEFAULT 0,`device_count_after` integer DEFAULT 0,`reset_by` varchar(50),`created_at` datetime);
CREATE TABLE `devices` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`subscription_id` integer,`device_fingerprint` varchar(255),`device_hash` varchar(255),`device_ua` varchar(255),`device_name` varchar(100),`device_type` varchar(50),`ip_address` varchar(45),`user_agent` text,`software_name` varchar(100),`software_version` varchar(50),`os_name` varchar(50),`os_version` varchar(50),`device_model` varchar(100),`device_brand` varchar(50),`subscription_type` varchar(20),`is_active` numeric DEFAULT true,`is_allowed` numeric DEFAULT true,`first_seen` datetime,`last_access` datetime,`last_seen` datetime,`access_count` integer DEFAULT 0,`created_at` datetime,`updated_at` datetime, `region` varchar(100));
CREATE TABLE `nodes` (`id` integer PRIMARY KEY AUTOINCREMENT,`name` varchar(100),`region` varchar(50),`type` varchar(20),`status` varchar(20) DEFAULT "offline",`load` real DEFAULT 0,`speed` real DEFAULT 0,`uptime` integer DEFAULT 0,`latency` integer DEFAULT 0,`description` text,`config` text,`is_recommended` numeric DEFAULT false,`is_active` numeric DEFAULT true,`is_manual` numeric DEFAULT false,`order_index` integer DEFAULT 0,`last_test` datetime,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `custom_nodes` (`id` integer PRIMARY KEY AUTOINCREMENT,`name` varchar(100),`display_name` varchar(100),`protocol` varchar(20),`domain` varchar(255),`port` integer DEFAULT 443,`config` text,`status` varchar(20) DEFAULT "inactive",`is_active` numeric DEFAULT true,`latency` integer DEFAULT 0,`last_test` datetime,`expire_time` datetime,`follow_user_expire` numeric DEFAULT false,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `user_custom_nodes` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`custom_node_id` integer,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `payment_callbacks` (`id` integer PRIMARY KEY AUTOINCREMENT,`payment_transaction_id` integer,`callback_type` varchar(50),`callback_data` json,`raw_request` text,`processed` numeric DEFAULT false,`processing_result` varchar(50),`error_message` text,`created_at` datetime);
CREATE TABLE `payment_configs` (`id` integer PRIMARY KEY AUTOINCREMENT,`pay_type` varchar(50),`app_id` text,`merchant_private_key` text,`alipay_public_key` text,`wechat_app_id` text,`wechat_mch_id` text,`wechat_api_key` text,`paypal_client_id` text,`paypal_secret` text,`stripe_publishable_key` text,`stripe_secret_key` text,`bank_name` text,`account_name` text,`account_number` text,`wallet_address` text,`status` integer DEFAULT 1,`return_url` text,`notify_url` text,`sort_order` integer DEFAULT 0,`config_json` json,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `invite_codes` (`id` integer PRIMARY KEY AUTOINCREMENT,`code` varchar(20),`user_id` integer,`used_count` integer DEFAULT 0,`max_uses` integer,`expires_at` datetime,`reward_type` varchar(20) DEFAULT "balance",`inviter_reward` decimal(10,2) DEFAULT 0,`invitee_reward` decimal(10,2) DEFAULT 0,`package_ids` text,`min_order_amount` decimal(10,2) DEFAULT 0,`new_user_only` numeric DEFAULT true,`is_active` numeric DEFAULT true,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `invite_relations` (`id` integer PRIMARY KEY AUTOINCREMENT,`invite_code_id` integer,`inviter_id` integer,`invitee_id` integer,`inviter_reward_given` numeric DEFAULT false,`invitee_reward_given` numeric DEFAULT false,`inviter_reward_amount` decimal(10,2) DEFAULT 0,`invitee_reward_amount` decimal(10,2) DEFAULT 0,`invitee_first_order_id` integer,`invitee_total_consumption` decimal(10,2) DEFAULT 0,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `notifications` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`title` varchar(255),`content` text,`type` varchar(50) DEFAULT "system",`is_read` numeric DEFAULT false,`is_active` numeric DEFAULT true,`created_at` datetime,`updated_at` datetime,`read_at` datetime);
CREATE TABLE `email_templates` (`id` integer PRIMARY KEY AUTOINCREMENT,`name` varchar(100),`subject` varchar(200),`content` text,`variables` text,`is_active` numeric DEFAULT true,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `email_queue` (`id` integer PRIMARY KEY AUTOINCREMENT,`to_email` varchar(100),`subject` varchar(200),`content` text,`content_type` varchar(20) DEFAULT "plain",`email_type` varchar(50),`attachments` text,`status` varchar(20) DEFAULT "pending",`retry_count` integer DEFAULT 0,`max_retries` integer DEFAULT 3,`sent_at` datetime,`error_message` text,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `tickets` (`id` integer PRIMARY KEY AUTOINCREMENT,`ticket_no` varchar(50),`user_id` integer,`title` varchar(200),`content` text,`type` varchar(20) DEFAULT "other",`status` varchar(20) DEFAULT "pending",`priority` varchar(20) DEFAULT "normal",`assigned_to` integer,`admin_notes` text,`rating` integer,`rating_comment` text,`created_at` datetime,`updated_at` datetime,`resolved_at` datetime,`closed_at` datetime);
CREATE TABLE `ticket_replies` (`id` integer PRIMARY KEY AUTOINCREMENT,`ticket_id` integer,`user_id` integer,`content` text,`is_admin` numeric DEFAULT false,`is_read` numeric DEFAULT false,`read_by` integer,`read_at` datetime,`created_at` datetime);
CREATE TABLE `ticket_attachments` (`id` integer PRIMARY KEY AUTOINCREMENT,`ticket_id` integer,`reply_id` integer,`file_name` varchar(255),`file_path` varchar(500),`file_size` integer,`file_type` varchar(50),`uploaded_by` integer,`created_at` datetime);
CREATE TABLE `ticket_reads` (`id` integer PRIMARY KEY AUTOINCREMENT,`ticket_id` integer,`user_id` integer,`read_at` datetime,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `system_configs` (`id` integer PRIMARY KEY AUTOINCREMENT,`key` varchar(100),`value` text,`type` varchar(50),`category` varchar(50),`display_name` varchar(100),`description` text,`is_public` numeric DEFAULT false,`sort_order` integer DEFAULT 0,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `announcements` (`id` integer PRIMARY KEY AUTOINCREMENT,`title` varchar(200),`content` text,`type` varchar(50) DEFAULT "info",`is_active` numeric DEFAULT true,`is_pinned` numeric DEFAULT false,`start_time` datetime,`end_time` datetime,`target_users` varchar(50) DEFAULT "all",`created_by` integer,`created_at` datetime,`updated_at` datetime);
CREATE TABLE `theme_configs` (`id` integer PRIMARY KEY AUTOINCREMENT,`name` varchar(100) NOT NULL,`display_name` varchar(100) NOT NULL,`is_active` numeric DEFAULT false,`is_default` numeric DEFAULT false,`config` text,`preview_image` varchar(200),`created_at` datetime,`updated_at` datetime);
CREATE TABLE `audit_logs` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`action_type` varchar(50) NOT NULL,`resource_type` varchar(50),`resource_id` integer,`action_description` text,`ip_address` varchar(45),`user_agent` text,`location` varchar(255),`request_method` varchar(10),`request_path` varchar(255),`request_params` text,`response_status` integer,`before_data` text,`after_data` text,`created_at` datetime);
CREATE TABLE `login_attempts` (`id` integer PRIMARY KEY AUTOINCREMENT,`username` varchar(100) NOT NULL,`ip_address` varchar(45),`success` numeric DEFAULT false,`user_agent` varchar(500),`created_at` datetime NOT NULL);
CREATE TABLE `login_history` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer NOT NULL,`login_time` datetime,`logout_time` datetime,`ip_address` varchar(45),`user_agent` text,`location` varchar(100),`device_fingerprint` varchar(255),`login_status` varchar(20) DEFAULT "success",`failure_reason` text,`session_duration` integer);
CREATE TABLE `user_activities` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer NOT NULL,`activity_type` varchar(50) NOT NULL,`description` text,`ip_address` varchar(45),`user_agent` text,`location` varchar(100),`activity_metadata` text,`created_at` datetime);
CREATE TABLE `verification_codes` (`id` integer PRIMARY KEY AUTOINCREMENT,`email` varchar(100) NOT NULL,`code` varchar(6) NOT NULL,`created_at` datetime NOT NULL,`expires_at` datetime NOT NULL,`used` integer DEFAULT 0,`purpose` varchar(50) DEFAULT "register");
CREATE TABLE `verification_attempts` (`id` integer PRIMARY KEY AUTOINCREMENT,`email` varchar(100) NOT NULL,`ip_address` varchar(45),`success` numeric DEFAULT false,`purpose` varchar(50) DEFAULT "register",`created_at` datetime NOT NULL);
CREATE TABLE `registration_logs` (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer NOT NULL,`username` varchar(50) NOT NULL,`email` varchar(100) NOT NULL,`ip_address` varchar(45),`user_agent` text,`location` varchar(255),`register_source` varchar(50),`invite_code` varchar(20),`inviter_id` integer,`status` varchar(20) DEFAULT "success",`failure_reason` text,`created_at` datetime);
CREATE TABLE `subscription_logs` (`id` integer PRIMARY KEY AUTOINCREMENT,`subscription_id` integer NOT NULL,`user_id` integer NOT NULL,`action_type` varchar(50) NOT NULL,`action_by` varchar(50),`action_by_user_id` integer,`before_data` text,`after_data` text,`description` text,`ip_address` varchar(45),`location` varchar(255),`created_at` datetime);
CREATE TABLE `system_logs` (`id` integer PRIMARY KEY AUTOINCREMENT,`level` varchar(10) NOT NULL,`module` varchar(50) NOT NULL,`message` text NOT NULL,`detail` text,`created_at` datetime);
CREATE TABLE IF NOT EXISTS "user_levels"  (`id` integer PRIMARY KEY AUTOINCREMENT,`level_name` varchar(50),`level_order` integer,`min_consumption` decimal(10,2) DEFAULT 0,`discount_rate` decimal(5,2) DEFAULT 1,`device_limit` integer DEFAULT 3,`benefits` text,`icon_url` varchar(255),`color` varchar(20) DEFAULT "#909399",`is_active` numeric DEFAULT true,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "orders"  (`id` integer PRIMARY KEY AUTOINCREMENT,`order_no` varchar(50),`user_id` integer,`package_id` integer,`amount` decimal(10,2),`status` varchar(20) DEFAULT "pending",`payment_method_id` integer,`payment_method_name` varchar(100),`payment_time` datetime,`payment_transaction_id` varchar(100),`expire_time` datetime,`coupon_id` integer,`discount_amount` decimal(10,2) DEFAULT 0,`final_amount` decimal(10,2),`extra_data` text,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "packages"  (`id` integer PRIMARY KEY AUTOINCREMENT,`name` varchar(100),`description` text,`price` decimal(10,2),`duration_days` integer,`device_limit` integer DEFAULT 3,`sort_order` integer DEFAULT 1,`is_active` numeric DEFAULT true,`is_recommended` numeric DEFAULT false,`created_at` datetime,`updated_at` datetime,`traffic_limit` integer DEFAULT 0,`speed_limit` integer DEFAULT 0,`features` text,`is_featured` numeric DEFAULT false);
CREATE TABLE IF NOT EXISTS "payment_transactions"  (`id` integer PRIMARY KEY AUTOINCREMENT,`order_id` integer,`user_id` integer,`payment_method_id` integer,`amount` decimal(10,2),`currency` varchar(10) DEFAULT "CNY",`transaction_id` varchar(100),`external_transaction_id` varchar(100),`status` varchar(20) DEFAULT "pending",`payment_data` json,`callback_data` json,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "coupons"  (`id` integer PRIMARY KEY AUTOINCREMENT,`code` varchar(50),`name` varchar(100),`description` text,`type` varchar(20),`discount_value` decimal(10,2),`min_amount` decimal(10,2) DEFAULT 0,`max_discount` decimal(10,2),`valid_from` datetime,`valid_until` datetime,`total_quantity` integer,`used_quantity` integer DEFAULT 0,`max_uses_per_user` integer DEFAULT 1,`status` varchar(20) DEFAULT "active",`applicable_packages` text,`created_by` integer,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "coupon_usages"  (`id` integer PRIMARY KEY AUTOINCREMENT,`coupon_id` integer,`user_id` integer,`order_id` integer,`discount_amount` decimal(10,2),`used_at` datetime);
CREATE TABLE IF NOT EXISTS "recharge_records"  (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`order_no` varchar(50),`amount` decimal(10,2),`status` varchar(20) DEFAULT "pending",`payment_method` varchar(50),`payment_transaction_id` varchar(100),`payment_qr_code` text,`payment_url` text,`ip_address` varchar(45),`user_agent` text,`paid_at` datetime,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "balance_logs"  (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer NOT NULL,`change_type` varchar(50) NOT NULL,`amount` decimal(10,2) NOT NULL,`balance_before` decimal(10,2) NOT NULL,`balance_after` decimal(10,2) NOT NULL,`related_order_id` integer,`related_record_id` integer,`description` text,`operator` varchar(50),`operator_user_id` integer,`ip_address` varchar(45),`location` varchar(255),`created_at` datetime);
CREATE TABLE IF NOT EXISTS "commission_logs"  (`id` integer PRIMARY KEY AUTOINCREMENT,`inviter_id` integer NOT NULL,`invitee_id` integer NOT NULL,`invite_relation_id` integer,`commission_type` varchar(50) NOT NULL,`amount` decimal(10,2) NOT NULL,`related_order_id` integer,`status` varchar(20) DEFAULT "pending",`settled_at` datetime,`description` text,`created_at` datetime);
CREATE TABLE IF NOT EXISTS "redeem_codes"  (`id` integer PRIMARY KEY AUTOINCREMENT,`code` varchar(32) NOT NULL,`type` varchar(20) NOT NULL,`value` decimal(10,2) NOT NULL,`package_id` integer,`name` varchar(100) NOT NULL,`status` varchar(20) DEFAULT "unused",`max_uses` integer DEFAULT 1,`used_count` integer DEFAULT 0,`expires_at` datetime,`created_by` integer NOT NULL,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "redeem_records"  (`id` integer PRIMARY KEY AUTOINCREMENT,`redeem_code_id` integer NOT NULL,`user_id` integer NOT NULL,`code` varchar(32) NOT NULL,`type` varchar(20) NOT NULL,`value` decimal(10,2) NOT NULL,`ip_address` varchar(45),`created_at` datetime);
CREATE TABLE IF NOT EXISTS "check_ins"  (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`amount` decimal(10,2),`created_at` datetime);
CREATE TABLE IF NOT EXISTS "mystery_box_pools"  (`id` integer PRIMARY KEY AUTOINCREMENT,`name` varchar(100),`description` text,`price` decimal(10,2),`is_active` numeric DEFAULT true,`sort_order` integer DEFAULT 0,`min_level` integer,`min_balance` decimal(10,2),`max_opens_per_day` integer,`max_opens_total` integer,`start_time` datetime,`end_time` datetime,`created_at` datetime,`updated_at` datetime);
CREATE TABLE IF NOT EXISTS "mystery_box_prizes"  (`id` integer PRIMARY KEY AUTOINCREMENT,`pool_id` integer,`name` varchar(100),`type` varchar(20),`value` decimal(10,2),`weight` integer DEFAULT 1,`stock` integer,`image_url` varchar(255),`created_at` datetime,CONSTRAINT `fk_mystery_box_pools_prizes` FOREIGN KEY (`pool_id`) REFERENCES `mystery_box_pools`(`id`));
CREATE TABLE IF NOT EXISTS "mystery_box_records"  (`id` integer PRIMARY KEY AUTOINCREMENT,`user_id` integer,`pool_id` integer,`prize_id` integer,`prize_name` varchar(100),`prize_type` varchar(20),`prize_value` decimal(10,2),`cost` decimal(10,2),`created_at` datetime);
